'use client'

import Button, { type ButtonProps } from '@mui/material/Button'

const CTA_SX = {
  height: 36,
  minHeight: 36,

  borderRadius: '8px',

  fontSize: '0.875rem',
  fontWeight: 600,
  textTransform: 'none',

  px: 2,
  py: 0,

  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',

  lineHeight: 1,
}

export default function SecondaryCta({
  children,
  sx,
  ...rest
}: ButtonProps) {
  return (
    <Button
      variant='outlined'
      sx={{
        ...CTA_SX,

        backgroundColor: '#FFFFFF',
        color: '#1F1F1F',

        borderColor: 'var(--border)',

        boxShadow: 'none',

        '&:hover': {
          backgroundColor: '#FAFAFB',
          borderColor: 'var(--border)',
          boxShadow: 'none',
        },

        ...sx,
      }}
      {...rest}
    >
      {children}
    </Button>
  )
}